import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as o,o as i,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Moderación de imágenes y modo de acceso","description":"","frontmatter":{},"headers":[],"relativePath":"es/Safety/image-moderation-and-access-mode.md","filePath":"es/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"es/Safety/image-moderation-and-access-mode.md"};function s(c,e,n,l,m,p){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="moderacion-de-imagenes-y-modo-de-acceso" tabindex="-1">Moderación de imágenes y modo de acceso <a class="header-anchor" href="#moderacion-de-imagenes-y-modo-de-acceso" aria-label="Permalink to &quot;Moderación de imágenes y modo de acceso&quot;">​</a></h1><p>La moderación de imágenes y el modo de acceso controlan qué archivos pueden ver los visitantes según reglas públicas, listas y clasificación de edad.</p><p>Se usan junto con la galería pública, la API de imagen aleatoria y el acceso externo a archivos.</p><h2 id="que-permite-hacer" tabindex="-1">Qué permite hacer <a class="header-anchor" href="#que-permite-hacer" aria-label="Permalink to &quot;Qué permite hacer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Función</th><th>Descripción</th></tr></thead><tbody><tr><td>Moderación de imágenes</td><td>Registrar información de contenido o clasificación</td></tr><tr><td>Lista negra</td><td>Excluir archivos que no deben ser públicos</td></tr><tr><td>Modo lista blanca</td><td>Publicar solo archivos permitidos explícitamente</td></tr><tr><td>Control por edad</td><td>Ajustar visibilidad de R12, R16, R18 y similares</td></tr><tr><td>Modo de acceso</td><td>Cambiar de forma global el alcance visible para visitantes</td></tr></tbody></table><h2 id="modo-de-acceso" tabindex="-1">Modo de acceso <a class="header-anchor" href="#modo-de-acceso" aria-label="Permalink to &quot;Modo de acceso&quot;">​</a></h2><p>El modo de acceso limita lo que pueden devolver páginas públicas y API aleatoria.</p><p>Si quieres un sitio apto para todo público, configura el modo para devolver solo archivos generales. Para uso interno o acceso restringido, puedes ajustar reglas más flexibles.</p><h2 id="archivo-restringido" tabindex="-1">Archivo restringido <a class="header-anchor" href="#archivo-restringido" aria-label="Permalink to &quot;Archivo restringido&quot;">​</a></h2><p>Cuando un archivo queda restringido, el visitante ve un aviso en lugar del contenido original.</p><p><img src="'+a+'" alt="Archivo restringido" loading="lazy"></p><h2 id="formas-de-operar" tabindex="-1">Formas de operar <a class="header-anchor" href="#formas-de-operar" aria-label="Permalink to &quot;Formas de operar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Enfoque</th><th>Cuándo conviene</th></tr></thead><tbody><tr><td>Lista negra</td><td>Publicas por defecto y excluyes archivos problemáticos</td></tr><tr><td>Lista blanca</td><td>Solo publicas lo revisado y permitido</td></tr><tr><td>Clasificación por edad</td><td>Cambias la visibilidad según nivel de contenido</td></tr></tbody></table><p>Para sitios públicos, lista blanca o clasificación por edad ayudan a evitar publicaciones no deseadas.</p><h2 id="que-comprobar" tabindex="-1">Qué comprobar <a class="header-anchor" href="#que-comprobar" aria-label="Permalink to &quot;Qué comprobar&quot;">​</a></h2><ol><li>Revisa si el archivo aparece en la galería pública.</li><li>Comprueba que la API aleatoria no devuelva archivos restringidos.</li><li>Tras cambiar listas, ten en cuenta caché o resultados ya generados.</li><li>Si usas clasificación automática, revisa manualmente archivos sensibles porque puede haber errores de modelo.</li></ol>',16)])])}const g=o(d,[["render",s]]);export{b as __pageData,g as default};
